// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.EnumMap;
import java.util.List;
import java.util.Map;

import org.eclipse.rdf4j.query.algebra.equivalence.AlgebraEquivalenceChecker;
import org.eclipse.rdf4j.query.algebra.equivalence.EquivalenceStatus;
import org.junit.jupiter.api.Test;

/**
 * Guards against soundness fixes silently degrading the checker to always-UNKNOWN: a fixed, deterministically
 * regenerated pair set has its exact verdicts pinned in {@code fuzz/completeness-ledger.csv}. A fix that legitimately
 * moves a verdict forces a visible one-line ledger diff. Every run also writes the freshly computed ledger to
 * {@code target/completeness-ledger-bootstrap.csv} — copy it over the resource after an intentional behaviour change.
 */
class CheckerCompletenessGuardTest {
	private static final long LEDGER_SEED = 0xC0FFEE;
	private static final int LEDGER_PAIRS = 40;
	// Measured 21 EQUIVALENT / 19 UNKNOWN on the ledger seed; the floor carries slack so only a
	// collapse (not normal drift) trips it — the exact ledger pins the rest. NOT_EQUIVALENT
	// coverage is guarded by the pinned counterexample regressions
	// (JsonTupleExprCounterexampleTest, JsonTupleExprSoundnessRegressionTest), not by this set.
	private static final int MINIMUM_EQUIVALENT = 15;

	@Test
	void verdictsMatchTheLedgerExactly() throws IOException {
		List<String> computed = computeLedger();
		Files.createDirectories(Path.of("target"));
		Files.write(Path.of("target", "completeness-ledger-bootstrap.csv"), computed, StandardCharsets.UTF_8);

		List<String> pinned = pinnedLedger();
		assertEquals(String.join("\n", pinned), String.join("\n", computed),
				"checker verdicts drifted from fuzz/completeness-ledger.csv — if the change is intentional, "
						+ "review the diff and copy target/completeness-ledger-bootstrap.csv over the resource");
	}

	@Test
	void aggregateProofFloorsHold() {
		Map<EquivalenceStatus, Integer> counts = new EnumMap<>(EquivalenceStatus.class);
		for (TreePair pair : ledgerPairs()) {
			EquivalenceStatus status = new AlgebraEquivalenceChecker(FuzzProfile.primary(48).options())
					.check(pair.original(), pair.candidate())
					.getStatus();
			counts.merge(status, 1, Integer::sum);
		}
		assertTrue(counts.getOrDefault(EquivalenceStatus.EQUIVALENT, 0) >= MINIMUM_EQUIVALENT,
				"proof coverage collapsed: " + counts);
	}

	private List<TreePair> ledgerPairs() {
		return new RandomTreePairSource().pairs(LEDGER_SEED, LEDGER_PAIRS);
	}

	private List<String> computeLedger() {
		List<String> rows = new ArrayList<>();
		for (TreePair pair : ledgerPairs()) {
			EquivalenceStatus status = new AlgebraEquivalenceChecker(FuzzProfile.primary(48).options())
					.check(pair.original(), pair.candidate())
					.getStatus();
			rows.add(pair.label() + "," + String.join("+", pair.mutatorChain()) + "," + status);
		}
		return rows;
	}

	private List<String> pinnedLedger() throws IOException {
		try (InputStream input = getClass().getResourceAsStream(
				"/org/eclipse/rdf4j/query/algebra/equivalence/internal/fuzz/completeness-ledger.csv")) {
			assertTrue(input != null, "missing fuzz/completeness-ledger.csv — bootstrap it from "
					+ "target/completeness-ledger-bootstrap.csv");
			List<String> rows = new ArrayList<>();
			for (String line : new String(input.readAllBytes(), StandardCharsets.UTF_8).split("\n")) {
				if (!line.trim().isEmpty()) {
					rows.add(line.trim());
				}
			}
			return rows;
		}
	}
}
